const fs = require('fs');
const trackerPath = '/workspace/04_Produccion/pipeline_tracker.json';

let tracker = {};
try {
  const raw = fs.readFileSync(trackerPath, 'utf8');
  tracker = JSON.parse(raw);
} catch (e) {
  return [{ json: { resumen: 'Sin piezas registradas en el tracker.', stats: {} } }];
}

const piezas = Object.keys(tracker);
const ahora = new Date();
const stats = {
  total: piezas.length,
  por_estado: {},
  bloqueadas_48h: []
};

for (const p of piezas) {
  const estado = tracker[p].estado_actual || 'DESCONOCIDO';
  stats.por_estado[estado] = (stats.por_estado[estado] || 0) + 1;

  // Detectar piezas bloqueadas > 48h
  const ultimaAct = new Date(tracker[p].ultima_actualizacion);
  const horasDiff = (ahora - ultimaAct) / 3600000;
  if (horasDiff > 48 && estado !== 'PUBLISHED') {
    stats.bloqueadas_48h.push(`${p} (${estado}, ${Math.floor(horasDiff)}h sin cambio)`);
  }
}

// Formatear resumen
let resumen = `📊 *PIPELINE STATUS — ${ahora.toISOString().split('T')[0]}*\n\n`;
resumen += `Total piezas: ${stats.total}\n\n`;
resumen += `*Por estado:*\n`;
for (const [estado, count] of Object.entries(stats.por_estado)) {
  resumen += `  • ${estado}: ${count}\n`;
}

if (stats.bloqueadas_48h.length > 0) {
  resumen += `\n⚠️ *Bloqueadas >48h:*\n`;
  for (const b of stats.bloqueadas_48h) {
    resumen += `  • ${b}\n`;
  }
} else {
  resumen += `\n✅ Sin piezas bloqueadas.\n`;
}

return [{ json: { resumen, stats } }];

const fs = require('fs');
const logPath = '/workspace/07_Operaciones/FG_Operations_Log.md';
const stats = $input.first().json.stats;
const today = new Date().toISOString().split('T')[0];
const time = new Date().toISOString().split('T')[1].substring(0, 5);

const logLine = `| ${today} | ${time} | DAILY_STATUS | — | Total: ${stats.total || 0}, Bloqueadas: ${(stats.bloqueadas_48h || []).length} |`;

let content = '';
try {
  content = fs.readFileSync(logPath, 'utf8');
} catch (e) {
  content = `# FG Operations Log\n\n| Fecha | Hora | Evento | Pieza | Detalles |\n|-------|------|--------|-------|----------|\n`;
}

content += logLine + '\n';
fs.writeFileSync(logPath, content, 'utf8');

return [{ json: { logged: true } }];
